# @cctt_verify {"v":2,"sym":"sympy.physics.quantum.tests.test_dagger.test_dagger_mul","kind":"function","src_hash":"f8e343ef1ddc319a","in":{"base":"Any"},"out":{"base":"Any","pred":"Dagger(O) * O == Dagger(O) * O and Dagger(O) * Dagger(O) == Dagger(O) ** 2 and Dagger(O) * Dagger(I) == Dagger(O) and Dagger(O) * O * I == Mul(Dagger(O), O) * I"},"spec":{"lhs":"test_dagger_mul()","rhs":"test_dagger_mul produces the expected output","over":{"base":"Any"},"name":"test_dagger_mul_correct"},"guarantee":"test_dagger_mul produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.physics.quantum.tests.test_dagger.test_dagger_mul_correct","statement":"Path(test_dagger_mul(x), test_dagger_mul produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a3bab7df07fb0819"}
def test_dagger_mul():
    O = Operator('O')
    assert Dagger(O)*O == Dagger(O)*O
    with warns_deprecated_sympy():
        I = IdentityOperator()
        assert Dagger(O)*O*I == Mul(Dagger(O), O)*I
    assert Dagger(O)*Dagger(O) == Dagger(O)**2
    assert Dagger(O)*Dagger(I) == Dagger(O)


